import{json,requireCommissioner,requireBindings,getConnection}from'./_shared.js';
export async function onRequestGet({request,env}){const auth=requireCommissioner(request,env);if(auth)return auth;const binding=requireBindings(env);if(binding)return binding;try{const row=await getConnection(env);return json({connected:!!row?.connected,guildId:row?.guild_id||env.DISCORD_GUILD_ID,guildName:row?.guild_name||'',channelId:row?.channel_id||'',channelName:row?.channel_name||'',lastTestedAt:row?.last_tested_at||'',updatedAt:row?.updated_at||''})}catch(e){return json({error:e.message},500)}}
